class Solution:
    def maxBalancedSubarray(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            x = 0
            even = 0
            odd = 0
            for j in range(i, n):
                x ^= nums[j]
                if nums[j] % 2 == 0:
                    even += 1
                else:
                    odd += 1
                if x == 0 and even == odd:
                    length = j - i + 1
                    if length > best:
                        best = length
        return best

