class Solution:
    def maxBalancedSubarray(self, nums: List[int]) -> int:
        first = {(0, 0): 0}
        px = 0
        pc = 0
        best = 0
        for i, x in enumerate(nums, 1):
            px ^= x
            pc += 1 if x % 2 == 1 else -1
            key = (px, pc)
            if key in first:
                gap = i - first[key]
                if gap > best:
                    best = gap
            else:
                first[key] = i
        return best

