var maxBalancedSubarray = function(nums) {
    const first = new Map();
    first.set('0,0', 0);
    let px = 0, pc = 0, best = 0;
    for (let i = 0; i < nums.length; i++) {
        px ^= nums[i];
        pc += (nums[i] % 2 === 1) ? 1 : -1;
        const key = px + ',' + pc;
        if (first.has(key)) {
            const gap = (i + 1) - first.get(key);
            if (gap > best) best = gap;
        } else {
            first.set(key, i + 1);
        }
    }
    return best;
};
